var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......결국 이렇게 됐네.","JPN":"……結局はこんなもんか。","ENG":"... I can't believe this happened.","TWN":"……最後還是變成這樣了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_13"},{"id":"L4_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"달랑 머리만 남아서 이렇게 말하고 있다니.","JPN":"頭だけぽつんと取り残されて、一人ぼやいて終わる\\n運命だなんて。","ENG":"I'm just a talking head now.","TWN":"竟然只剩下頭部在說話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"이런 건 별로 멋지지 않은데 말이야.","JPN":"まったくもってイケてないな。","ENG":"This is not cool. Not cool at all.","TWN":"這個看起來一點都不美觀呀。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"R4의 상태를 점검합니다.","JPN":"R4の状態を確認します。","ENG":"Checking R4's condition...","TWN":"檢查R4的狀態。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......주동력기관의 영구적인 손상 감지.","JPN":"……主な動力機関の永久的な損傷を検知。","ENG":"... Permanent damage to main power system.","TWN":"……已檢測到主動力機關永久性受損。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":" 수복 가능성...... 0%","JPN":"修復可能性……0％。","ENG":" Possibility of recovery... 0%","TWN":" 修復成功率……0%。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"수복 가능성 재검토......","JPN":"修復可能性を再確認……","ENG":"Rescanning for possibility of recovery...","TWN":"重新檢查修復成功率。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"수복 가능성 재검토...... 수복 가능성 재검토...... 수복 가능성 재검토...... 수복 가능성 재검토...... 수복 가능성 재검토...... 수복 가능성 재검토......","JPN":"修復可能性を再確認……修復可能性を再確認……修復可能性を再確認……修復可能性を再確認……修復可能性を再確認……修復可能性を再確認……","ENG":"Rescanning for possibility of recovery... Rescanning for possibility of recovery... Rescanning for possibility of recovery... Rescanning for possibility of recovery... Rescanning for possibility of recovery... Rescanning for possibility of recovery...","TWN":"重新檢查修復成功率……重新檢查修復成功率……重新檢查修復成功率……重新檢查修復成功率……重新檢查修復成功率……重新檢查修復成功率……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"수복 가능성 재검토...... 수복 가능성 0%","JPN":"修復可能性を再確認……修復可能性0％","ENG":"Rescanning for possibility of recovery... Possibility of recovery: 0%.","TWN":"重新檢查修復成功率……修復成功率0%。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L13_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"됐어. 너무 신경 쓰지마.","JPN":"いいんだ、気にすることないよ。","ENG":"It's okay. Don't worry.","TWN":"行了，別費心了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"난...... 어차피 언제 죽어도 이상하지 않았어.","JPN":"ボクは……どうせいつ死んでもおかしくなかった。","ENG":"I... I knew I was going to die sooner or later.","TWN":"我……早就該離開這個世界了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"내게 허락된 시간은 이미 오래 전에 끝났으니까.","JPN":"ボクに許された時間はとっくのとうに終わってるからね。","ENG":"The time that was allotted to me expired a long time ago.","TWN":"我的時間早在很久之前就已經結束了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......내 몸에 쓰여있는 품질보증기한.","JPN":"……ボクの体に刻まれた品質保持期限。","ENG":"The product warranty period printed on my body...","TWN":"……我身上寫著的有效日期。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"이미 지난 지 한참 됐거든.","JPN":"とっくの昔に切れているんだ。","ENG":"I'm long past my expiration date.","TWN":"早就過期了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"뭐, 그게 아니더라도 보급형 로봇 주제에 이렇게나 오래 살다니 말이야. 지긋지긋했다고.","JPN":"まあ、安いロボットのくせに長生きしたしね。\\nそろそろ飽きたところだったんだ。","ENG":"Well, even if I wasn't, I lasted way longer than any other mass-produced robot. I'm tired of living.","TWN":"一個大眾型機器人活了這麼長時間，也是怪累的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"게다가......","JPN":"それに……","ENG":"Besides...","TWN":"而且……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"덕분에 주니어의 복수도 성공했으니 딱히 미련은 없어.","JPN":"おかげでジュニアの復讐も果たせたし、とくに未練はない。","ENG":"I also avenged Junior, thanks to you. I don't have any regrets now.","TWN":"多虧你，我報了尤尼奧爾的仇，我已經沒有什麼可留戀的了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그래. 복수랍시고 딱히 내가...... 도움은 안 됐지.","JPN":"復讐とはいってもボクが……貢献できたわけでもないけど。","ENG":"Well, actually, you did most of the avenging.","TWN":"唉，還說什麼報仇……我什麼忙都沒幫上。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L24_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"역시 너...... 엄청 세더라.","JPN":"キミ……さすがの腕前だったよ。","ENG":"You're really strong.","TWN":"不愧是你……真的好厲害。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......고마워.","JPN":"……ありがとう。","ENG":"... Thanks.","TWN":"……謝謝你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"빚을 졌으니 답례는 해야겠지.","JPN":"借りをつくったからには、お礼をしないとね。","ENG":"I want to repay you.","TWN":"我欠你一個人情，怎麼能不做答謝呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"미안한데, 나 손이 없거든.","JPN":"悪いけど、ボクにはもう手がなくてね。","ENG":"I'm sorry, but I don't have hands anymore.","TWN":"抱歉，我現在沒有手。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"답례는 내 몸통에서 직접 가져가줄래?","JPN":"お礼はボクの体から直接受け取ってくれるかい？","ENG":"Mind picking up your reward from my body on your own?","TWN":"能幫我從我的身體裡拿走回禮嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그 책. 가정집에서 쫓겨나기 전에 그 집 아이에게 선물로 받았던 거야.","JPN":"その本、働いていた家から追い出される前に、\\nその家の子どもからプレゼントでもらったんだ。","ENG":"That book. I got it from my child master before I got kicked out of his house.","TWN":"那本書是我被趕走之前，那家孩子送給我的禮物。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그 집 어른들은 날 싫어했지만, 우리 둘은 사이가 꽤 좋았거든.","JPN":"そこの大人たちには嫌われたけど、ボクらは結構\\n仲良しでね。","ENG":"His parents hated me, but he and I were pretty good friends.","TWN":"他們家大人都不喜歡我，但我和那個孩子關係很好。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그래서 간직하고 있었어. 그 애와 함께 했던 삶을 놓치고 싶지 않아서......","JPN":"だから大切にしてきた。その子との思い出を\\n失いたくなかったから。","ENG":"That's why I've been carrying it with me, to hold on to the life I shared with him.","TWN":"所以我一直收藏著這本書，我不想忘掉我和那個孩子一起度過的時光……"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"어쩌면...... 그게 내가 지금까지 악착같이 살아온 원동력이었던 것 같아.","JPN":"もしかしたら……ボクがこれまで必死に生きて\\nこられたのは、それのおかげかもしれない。","ENG":"Maybe it's what fueled me to keep going.","TWN":"或許……那就是讓我拼命活到現在的動力。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그렇게 살아가다, 또 새 가족과 새 삶을 찾고, 그렇게 살아갈 힘을 얻으며 지냈지.","JPN":"そこから生き続けて、新しい家族や人生を\\n手に入れて、生きる力を得ていたんだ。","ENG":"I kept going, to find new families and build new lives with them, and keep on living that way.","TWN":"我拼命活著，找到新的家人和新的人生，獲得生活的動力。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"내가 지금껏 살아왔던 건...... 나의 가족도, 날 위해서도 아냐.","JPN":"ボクがこれまで生きてこられたのは……ボクの\\n家族のためでも、ボク自身のためでもない。","ENG":"But I didn't live for them or myself;","TWN":"我活到現在……不是為了我的家人，也不是為了我自己。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"여러 가족을 만났던 나의 삶이 그렇게 해서라도 지킬만한 가치가 있다고 믿었기 때문이야.","JPN":"様々な家族とめぐり会えた自分の人生に、守るべき\\n価値があると信じたからなんだ。","ENG":"I lived because I believed that my life was worth living.","TWN":"而是因為我堅信，認識許多家人的人生值得我拼命守護。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"내가 태어난 이유를 따라 그저 청소만 하고 살았다면, 이렇게 악착같이 버티진 못했겠지.","JPN":"ボクが生まれた理由に従って掃除だけをしていたら、ここまであがいてこれなかったと思う。","ENG":"I wouldn't have lasted this long if I simply followed my original purpose, which is cleaning.","TWN":"如果我遵循我被製造出來的目的，每天只知道打掃衛生，就不可能堅持到現在。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그러니까, 너도...... 임무가 아닌 너만의 삶을 찾아.","JPN":"だから、キミも……任務をこなすだけではなく、\\nキミだけの人生を生きて。","ENG":"I'm saying... you should find your own life, instead of following your mission.","TWN":"所以，你也……別整天做任務，活出自己的人生吧。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"너의 가족을 만들고, 가치 있는 삶을 살아.","JPN":"キミの家族をつくって、価値のある人生を生きるんだ。","ENG":"Create your own family and live a life worth living.","TWN":"打造你的家庭，度過有價值的人生吧。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그 책은, 네가 그렇게 될 때까지 무사하길 바라는 의미로 주는 부적이야.","JPN":"キミがそうなるまで無事でいられるように、その本は\\nお守りとしてプレゼントするよ。","ENG":"I'm giving you that book because I want it to keep you safe until you achieve that.","TWN":"那本書是我給你的符咒，它會保護你直到你活出屬於自己的人生。"},"stage":{"bg":"EV_SIGMA_11","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"아 참.","JPN":"あ、そうだ。","ENG":"And one more thing.","TWN":"對了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......넌 복수 같은 거 하지마.","JPN":"……キミは復讐なんてしないでね。","ENG":"Don't try to avenge me.","TWN":"……你千萬不要執著於報仇。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......그럼.","JPN":"……それじゃあ。","ENG":"Now...","TWN":"……那麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L50_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"좋은 밤 되렴.","JPN":"おやすみ、いい夢を。","ENG":"Good night.","TWN":"晚安。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하루는 나무를 하러 나간 나무꾼이 돌아오지 않았습니다.","JPN":"ある日、木こりは仕事から戻ってきませんでした。","ENG":"One day, the woodcutter went out to cut down trees and didn't come back.","TWN":"有一天，出去砍柴的樵夫沒有再回家。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 나무꾼에게 나쁜 일이 생겼을까 걱정했습니다.","JPN":"少女は木こりに何か悪いことが起きたのではないかと\\n心配しました。","ENG":"The girl started to get worried.","TWN":"少女擔心樵夫遇到了危險。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"문을 열기 전, 혼자선 절대 숲으로 들어가지 말라던 나무꾼의 말이 떠올랐습니다.","JPN":"少女がドアを開ける直前、木こりからひとりでは決して森に入らないように念を押されていたことを思い出しました。","ENG":"She was about to open the door to the outside when she remembered that her father told her never to enter the forest by herself.","TWN":"她想起樵夫的囑咐，讓自己千萬不要進入森林。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"말을 잘 듣는 딸이 되고 싶었지만, 그랬다간 나무꾼을 영영 만나지 못할 것 같았습니다.","JPN":"少女はその言葉を守りたかったものの、このままでは\\n二度と木こりに会えない気がしました。","ENG":"She wanted to be a dutiful daughter, but she didn't want to lose her father, either.","TWN":"她想成為一個聽話的乖女兒，但她更害怕以後永遠見不到樵夫。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 소녀는 용기를 내어 나무꾼을 찾아 길을 떠나기로 했답니다.","JPN":"そのため、少女は勇気をふり絞り、木こりを\\nさがしにいこうと決意したのです。","ENG":"She plucked up her courage and set off on a journey to find him.","TWN":"於是少女鼓起勇氣出門，去尋找樵夫。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"정보 오염 감지.","JPN":"情報汚染を検知。","ENG":"Data corruption detected.","TWN":"檢測到資訊污染。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"원인...... 외부 충격으로 인한 이터니움 실드 손상으로 추정","JPN":"原因……外部からの衝撃によるエタニウムシールドの\\n損傷と想定。","ENG":"Possible cause: Eternium shield damage by external impact.","TWN":"原因……推測為外部衝擊導致能晶盾受損。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"관리국 정보관리 규정에 의거, 오염되지 않은 데이터를 우선적으로 보호하기 위해 침식된 데이터의 분리 및 제거 작업을 시작합니다.","JPN":"管理局の情報管理規程に基づき、汚染されていない\\nデータを優先的に保護します。そのため、侵食された\\nデータの分離および除去を開始します。","ENG":"In accordance with the Administration's information management policy, the Corrupted data will be separated and removed to prevent spreading.","TWN":"根據管理局資訊管理規定，為了保護未污染的資料，開始分離並刪除被侵蝕的資料。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......작업 종료.","JPN":"……対応終了。","ENG":"... Task completed.","TWN":"……工作完畢。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"나는......","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"왜 여기에......","JPN":"なぜここに……","ENG":"Why am I here?","TWN":"為什麼我在這裡……"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"사고 혼란 감지. 긴급 프로세스 가동.","JPN":"事故による混乱を検知。緊急プロセスを稼働。","ENG":"Detected confusion in thought processes. Activating emergency protocol...","TWN":"感知到思維混亂，啟動緊急程式。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"명령권자의 직접 지시가 있기 전까지 비상 절전 체제에 돌입합니다.","JPN":"命令権者の直接指示があるまで、非常時の\\n省電力モードに入ります。","ENG":"Entering emergency energy saving mode until Administrator's direct order is received...","TWN":"進入緊急省電模式，直到接收命令權者的直接指示。"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"시스템...... 종료......","JPN":"システム……終了……","ENG":"Shutting down system...","TWN":"系統……關閉……"},"stage":{"bg":"EV_SIGMA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};